import React, { Component } from 'react'
import MenuItem from '../components/MenuItem'

import me from '../img/me.jpg'

export default class Menu extends Component {
    state = {
        active: [true,false,false,false,false,false,false]
    }

    componentDidUpdate(prevProps){
        if(prevProps.active !== this.props.active){
            let arr = [false,false,false,false,false,false,false]
            if(this.props.active !== -1) {
                arr[this.props.active] = true;
            }
            this.setState({active: arr})
        }
    }

    render() {
        return (
            <div className="shadow-2xl fixed w-1/6 h-screen z-50 bg-white">
                <div className="w-full border-blue-400 border-b-2 py-5 flex flex-wrap items-center justify-center">
                    <img className="rounded-full w-1/2 block border-4 border-blue-400 my-2" src={me} alt=""/>
                    <p className="text-3xl text-blue-600 w-full text-center">Daniel Melchor</p>
                </div>
                <div className="pt-5">
                    <MenuItem text="About" color="#1cc8e8" icon="fas fa-user" linkTo="#about" activeNow={this.state.active[0]} />
                    <MenuItem text="Experience" color="#1baae9" icon="fas fa-user-tie" linkTo="#experience" activeNow={this.state.active[1]} />
                    <MenuItem text="Projects" color="#0092ff" icon="fas fa-tools" linkTo="#projects" activeNow={this.state.active[2]} />
                    <MenuItem text="Skills" color="#0077ff" icon="fas fa-chart-bar" linkTo="#skills" activeNow={this.state.active[3]} />
                    <MenuItem text="Education" color="#0042ff" icon="fas fa-graduation-cap" linkTo="#education" activeNow={this.state.active[4]} />
                    <MenuItem text="Contact" color="#001fff" icon="fas fa-comment-dots" linkTo="#contact" activeNow={this.state.active[5]} />
                    <MenuItem text="Resume" color="#2619c3" icon="fas fa-file" linkTo="#resume" activeNow={this.state.active[6]} />
                </div>
            </div>
        )
    }
}
